import{_ as e,o,c as a,ag as r}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"Autopilot","description":"","frontmatter":{},"headers":[],"relativePath":"robotics/autopilot.md","filePath":"robotics/autopilot.md"}'),i={name:"robotics/autopilot.md"};function l(n,t,s,h,u,d){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="autopilot" tabindex="-1">Autopilot <a class="header-anchor" href="#autopilot" aria-label="Permalink to &quot;Autopilot&quot;">​</a></h1><p>In the ArduSub control system, the autopilot board (also known as a flight controller) is the component which the ArduSub firmware is loaded onto. The autopilot processes the pilot input and sensor data, and controls the motors, lights, servos, and relays on the vehicle.</p><p>Although there are many different autopilot boards available, here are the general characteristics:</p><ul><li>Ability to load any ArduPilot binary firmware file (Copter, Plane, Rover/Boat, Sub)</li><li>Contains input and output connections for connecting multiple peripherals</li><li>Contains embedded IMU(s), magnetic compass(es) and gyroscope(s) to determine vehicle&#39;s orientation</li><li>Capable of saving vehicle logs</li></ul><h2 id="recommended-autopilots" tabindex="-1">Recommended Autopilots <a href="#recommended-autopilots" id="recommended-autopilots"></a> <a class="header-anchor" href="#recommended-autopilots" aria-label="Permalink to &quot;Recommended Autopilots &lt;a href=&quot;#recommended-autopilots&quot; id=&quot;recommended-autopilots&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>The first autopilot board recommended for ArduSub was the <a href="https://docs.px4.io/v1.10/en/flight_controller/pixhawk.html" target="_blank" rel="noreferrer">Pixhawk 1</a> manufactured by 3D Robotics (3DR) from 2013-2016. When 3DR exited manufacturing hardware in 2016, different manufacturers took the open source design files and created their own flight controllers.</p><p>The following list is the recommended autopilot boards for use with ArduSub:</p><ol><li>The original <a href="https://docs.px4.io/v1.10/en/flight_controller/pixhawk.html" target="_blank" rel="noreferrer">3DR (3D Robotics) Pixhawk 1</a></li><li><a href="https://docs.px4.io/v1.10/en/flight_controller/mro_pixhawk.html" target="_blank" rel="noreferrer">mRobotics (Mayan Robotics) Pixhawk 1</a></li></ol><h3 id="not-recommended-autopilots" tabindex="-1">Not Recommended Autopilots <a href="#not-recommended-autopilots" id="not-recommended-autopilots"></a> <a class="header-anchor" href="#not-recommended-autopilots" aria-label="Permalink to &quot;Not Recommended Autopilots &lt;a href=&quot;#not-recommended-autopilots&quot; id=&quot;not-recommended-autopilots&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>With feedback from other users, the following autopilot boards are not recommended for use with Ardusub:</p><ol><li><a href="https://docs.cubepilot.org/user-guides/autopilot/the-cube-module-overview" target="_blank" rel="noreferrer">Cube Module</a> (all colors) and corresponding carrier board <ul><li>Issue: Does not autoconnect to Companion computer with firmware v4.0 and above. <a href="https://github.com/bluerobotics/companion/issues/322" target="_blank" rel="noreferrer">Github Issue #322</a></li></ul></li><li><a href="https://www.foxtechfpv.com/pixhawk-autopilot-combo.html" target="_blank" rel="noreferrer">RadioLink Pixhawk</a><ul><li>Issues: Proprietary firmware binaries, only works with RadioLink version of Mission Planner, incorrect connectors.</li></ul></li><li>Any autopilot with <a href="https://www.molex.com/molex/products/family/picoblade" target="_blank" rel="noreferrer">Picoblade</a> series connectors instead of <a href="https://bluerobotics.com/learn/wl-connector-standard/#hirose-df13-series-not-recommended-for-new-designs" target="_blank" rel="noreferrer">DF13</a> connectors. <ul><li>Issue: Is not connector compatible with DF13, which is used on many Blue Robotics products.</li></ul></li></ol><h3 id="other-autopilots-that-haven-t-been-tested" tabindex="-1">Other Autopilots That Haven&#39;t Been Tested <a href="#other-autopilots-that-havent-been-tested" id="other-autopilots-that-havent-been-tested"></a> <a class="header-anchor" href="#other-autopilots-that-haven-t-been-tested" aria-label="Permalink to &quot;Other Autopilots That Haven&#39;t Been Tested &lt;a href=&quot;#other-autopilots-that-havent-been-tested&quot; id=&quot;other-autopilots-that-havent-been-tested&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>ArduPilot has has a list of other compatible autopilots: <a href="https://ardupilot.org/copter/docs/common-autopilots.html" target="_blank" rel="noreferrer">Autopilot Hardware Options</a></p><p>These boards have not been tested or reported to work with ArduSub.</p><h3 id="results-matching" tabindex="-1">results matching &quot;&quot; <a class="header-anchor" href="#results-matching" aria-label="Permalink to &quot;results matching &quot;&quot;&quot;">​</a></h3><ul><li></li></ul><h3 id="no-results-matching" tabindex="-1">No results matching &quot;&quot; <a class="header-anchor" href="#no-results-matching" aria-label="Permalink to &quot;No results matching &quot;&quot;&quot;">​</a></h3>',17)])])}const m=e(i,[["render",l]]);export{p as __pageData,m as default};
